import React from 'react';
import { View, Text, Button } from 'react-native';
import { InAppPurchaseManager, DigitalWalletManager } from 'react-native-payment-module';

class PaymentModule extends React.Component {
  constructor(props) {
    super(props);
    this.state = {
      purchaseStatus: '',
      walletBalance: 0,
    };
  }

  componentDidMount() {
    InAppPurchaseManager.init();
    DigitalWalletManager.init();
  }

  handleInAppPurchase = async () => {
    try {
      const result = await InAppPurchaseManager.purchase('product_id');
      this.setState({ purchaseStatus: `Purchased ${result.productName}` });
    } catch (error) {
      this.setState({ purchaseStatus: `Error: ${error.message}` });
    }
  };

  handleDigitalWalletTransaction = async () => {
    try {
      const result = await DigitalWalletManager.charge(10.99);
      this.setState({ walletBalance: result.balance, purchaseStatus: 'Transaction successful' });
    } catch (error) {
      this.setState({ purchaseStatus: `Error: ${error.message}` });
    }
  };

  render() {
    return (
      <View>
        <Text>Payment Module</Text>
        <Button title="Make In-App Purchase" onPress={this.handleInAppPurchase} />
        <Button title="Charge Digital Wallet" onPress={this.handleDigitalWalletTransaction} />
        <Text>{this.state.purchaseStatus}</Text>
        <Text>Digital Wallet Balance: ${this.state.walletBalance}</Text>
      </View>
    );
  }
}

export default PaymentModule;